module RefModule (
    input clk,
    input sreset,
    input load_enable,
    input shift,
    input [23:0] data,
    output [23:0] q );reg [23:0] unused_q_reg;

always @(posedge clk) begin
    if (sreset)
        unused_q_reg <= 24'b0;
    else if (load_enable)
        unused_q_reg <= data;
    else if (shift)
        unused_q_reg <= {unused_q_reg[22:0], 1'b0};
end

assign q = unused_q_reg;

endmodule
